function solve(configJson) {
  const config = JSON.parse(configJson);
  // 1. database.server.id -- обязателен для MySQL cluster topology
  config.config['database.server.id'] = '184054';
  // 2. snapshot.mode -- 'full' не существует, корректное значение 'initial'
  config.config['snapshot.mode'] = 'initial';
  // 3. schema.history.internal.kafka.topic -- обязателен для хранения DDL
  config.config['schema.history.internal.kafka.topic'] = 'schema-changes.inventory-db';
  return config;
}

