function solve(requirementsJson) {
  const reqs = JSON.parse(requirementsJson);
  return {
    name: reqs.serverName + '-connector',
    config: {
      'connector.class': 'io.debezium.connector.mysql.MySqlConnector',
      'database.hostname': reqs.hostname,
      'database.port': String(reqs.port),
      'database.user': reqs.user,
      'database.password': reqs.password,
      'database.server.id': String(reqs.serverId),
      'database.server.name': reqs.serverName,
      'table.include.list': reqs.tables.join(','),
      'schema.history.internal.kafka.topic': 'schema-changes.' + reqs.serverName,
      'schema.history.internal.kafka.bootstrap.servers': reqs.kafkaBootstrap,
      'snapshot.mode': 'initial'
    }
  };
}

