questions.solutionCode:
function solve(eventJson) {
  const event = JSON.parse(eventJson);
  const payload = event.payload;
  const operation = payload.op;
  const table = payload.source.table;
  const database = payload.source.db;
  // Для DELETE используем before, для остальных -- after
  const record = operation === 'd' ? payload.before : payload.after;
  const changedFields = Object.keys(record).sort();
  return {
    operation,
    table,
    database,
    changedFields
  };
}
